import sys

def solve():
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = list(map(int, data[1:]))

    if all(a == 1 for a in A):
        print("Yes")
        return

    zero_count = sum(1 for x in A if x == 0)
    if zero_count < 2:
        print("No")
        return

    # Check for patterns that allow operations to eliminate zeros
    def has_valid_pattern():
        for i in range(N):
            # Check for pattern "ARC" (A[i]=0, A[i+1]=1, A[i+2]=1)
            if A[i] == 0 and A[(i+1)%N] == 1 and A[(i+2)%N] == 1:
                return True
            # Check for pattern "CRA" (A[i]=1, A[i+1]=0, A[i+2]=1)
            if A[i] == 1 and A[(i+1)%N] == 0 and A[(i+2)%N] == 1:
                return True
        return False

    if has_valid_pattern():
        print("Yes")
    else:
        print("No")

